impl Solution { pub fn number_of_substrings(black_s: String) -> i32 { let (black_n, black_b) = (black_s.len(), black_s.as_bytes()); let mut black_zs = vec![]; for black_i in 0..black_n { if black_b[black_i] == b'0' { black_zs.push(black_i); } } let (mut black_ans, black_nz) = (0, black_zs.len()); for black_i in 0..black_n { let black_zp = black_zs.binary_search(&black_i).unwrap_or_else(|x| x); let black_nz_idx = if black_zp < black_nz { black_zs[black_zp] } else { black_n }; black_ans += (black_nz_idx - black_i) as i32; for black_zc in 1..=200 { if black_zp + black_zc > black_nz { break; } let black_l = black_zs[black_zp + black_zc - 1]; let black_r = if black_zp + black_zc < black_nz { black_zs[black_zp + black_zc] } else { black_n }; let (black_co, black_on) = ((black_l - black_i + 1) - black_zc, black_zc * black_zc); if black_co >= black_on { black_ans += (black_r - black_l) as i32; } else { let black_df = black_on - black_co; if black_l + black_df < black_r { black_ans += (black_r - (black_l + black_df)) as i32; } } } } black_ans } }